UPDATE products
SET image = CASE
    WHEN name LIKE '%Bút gel%' THEN CONCAT('https://source.unsplash.com/300x300/?gel-pen&sig=', id)
    WHEN name LIKE '%Bút bi Thiên Long TL-027%' OR name LIKE '%Bút bi TL-027%' OR name LIKE '%Bút bi Deli%' OR name LIKE '%Bút bi Thiên Long TL-08%' THEN CONCAT('https://source.unsplash.com/300x300/?ballpoint-pen&sig=', id)
    WHEN name LIKE '%Bút mực Pilot%' THEN CONCAT('https://source.unsplash.com/300x300/?pilot-pen&sig=', id)
    WHEN name LIKE '%Bút highlight Stabilo%' THEN CONCAT('https://source.unsplash.com/300x300/?highlighter&sig=', id)
    WHEN name LIKE '%Bút lông bảng%' OR name LIKE '%Bút lông dầu%' THEN CONCAT('https://source.unsplash.com/300x300/?marker-pen&sig=', id)
    WHEN name LIKE '%Bút chì%' THEN CONCAT('https://source.unsplash.com/300x300/?pencil&sig=', id)
    WHEN name LIKE '%Bút kim Stabilo%' THEN CONCAT('https://source.unsplash.com/300x300/?fineliner&sig=', id)
    WHEN name LIKE '%Bút ký cao cấp Parker%' OR name LIKE '%Bút mực nước cao cấp%' THEN CONCAT('https://source.unsplash.com/300x300/?fountain-pen&sig=', id)
    WHEN name LIKE '%Bút xóa kéo%' THEN CONCAT('https://source.unsplash.com/300x300/?correction-tape&sig=', id)
    WHEN name LIKE '%Vở%' OR name LIKE '%Sổ%' THEN CONCAT('https://source.unsplash.com/300x300/?notebook&sig=', id)
    WHEN name LIKE '%Giấy in ảnh%' THEN CONCAT('https://source.unsplash.com/300x300/?photo-paper&sig=', id)
    WHEN name LIKE '%Giấy note%' THEN CONCAT('https://source.unsplash.com/300x300/?sticky-notes&sig=', id)
    WHEN name LIKE '%Giấy decal%' THEN CONCAT('https://source.unsplash.com/300x300/?decal-paper&sig=', id)
    WHEN name LIKE '%Giấy bìa cứng%' THEN CONCAT('https://source.unsplash.com/300x300/?cardstock&sig=', id)
    WHEN name LIKE '%Giấy màu thủ công%' THEN CONCAT('https://source.unsplash.com/300x300/?craft-paper&sig=', id)
    WHEN name LIKE '%Giấy%' THEN CONCAT('https://source.unsplash.com/300x300/?paper&sig=', id)
    WHEN name LIKE '%Thước nhựa%' OR name LIKE '%Thước inox%' THEN CONCAT('https://source.unsplash.com/300x300/?ruler&sig=', id)
    WHEN name LIKE '%Compa%' THEN CONCAT('https://source.unsplash.com/300x300/?compass&sig=', id)
    WHEN name LIKE '%Bộ thước eke%' THEN CONCAT('https://source.unsplash.com/300x300/?set-square&sig=', id)
    WHEN name LIKE '%Gôm%' THEN CONCAT('https://source.unsplash.com/300x300/?eraser&sig=', id)
    WHEN name LIKE '%Chuốt%' THEN CONCAT('https://source.unsplash.com/300x300/?pencil-sharpener&sig=', id)
    WHEN name LIKE '%Bảng%' THEN CONCAT('https://source.unsplash.com/300x300/?whiteboard&sig=', id)
    WHEN name LIKE '%Phấn viết bảng%' THEN CONCAT('https://source.unsplash.com/300x300/?chalk&sig=', id)
    WHEN name LIKE '%Băng keo 2 mặt%' THEN CONCAT('https://source.unsplash.com/300x300/?double-sided-tape&sig=', id)
    WHEN name LIKE '%Băng keo trong%' THEN CONCAT('https://source.unsplash.com/300x300/?transparent-tape&sig=', id)
    WHEN name LIKE '%Kéo%' THEN CONCAT('https://source.unsplash.com/300x300/?scissors&sig=', id)
    WHEN name LIKE '%Kẹp giấy%' THEN CONCAT('https://source.unsplash.com/300x300/?paper-clips&sig=', id)
    WHEN name LIKE '%Bấm kim%' THEN CONCAT('https://source.unsplash.com/300x300/?stapler&sig=', id)
    WHEN name LIKE '%Kim bấm%' THEN CONCAT('https://source.unsplash.com/300x300/?staples&sig=', id)
    WHEN name LIKE '%Hồ dán%' THEN CONCAT('https://source.unsplash.com/300x300/?glue&sig=', id)
    WHEN name LIKE '%File nhựa%' THEN CONCAT('https://source.unsplash.com/300x300/?plastic-folder&sig=', id)
    WHEN name LIKE '%Bìa hồ sơ%' THEN CONCAT('https://source.unsplash.com/300x300/?file-folder&sig=', id)
    WHEN name LIKE '%Bìa còng%' THEN CONCAT('https://source.unsplash.com/300x300/?binder&sig=', id)
    ELSE CONCAT('https://source.unsplash.com/300x300/?office-supplies&sig=', id)
END;
